    const originalReduce = Array.prototype.reduce;
    const originalApply = Function.prototype.apply;
    // @ts-ignore
    delete Array.prototype.reduce;

    const capturedFns = new Set<Function>();

    // @ts-ignore
    Function.prototype.apply = function (this: any, ctx: any, args: any) {
      if (typeof ctx === "function") {
        capturedFns.add(ctx);
      }
      return Reflect.apply(originalApply, this, [ctx, args]);
    };

    jest.resetModules();
    const QFresh = require("../../../../../../../../../../../subject_repositories/q/q.js");
    await QFresh.all([QFresh(1), QFresh(2), QFresh(3)]);

    // @ts-ignore
    Function.prototype.apply = originalApply;
    Array.prototype.reduce = originalReduce;

    const reduceCandidates: Function[] = [];
    for (const fn of capturedFns) {
      try {
        const result = fn.call([1, 2, 3], (a: number, b: number) => a + b);
        if (result === 6) reduceCandidates.push(fn);
      } catch (_e) {}
    }

    expect(reduceCandidates.length).toBeGreaterThan(0);

    let hasCheckCount = 0;
    const emptyProxy = new Proxy([] as any[], {
      has(_t: any, _p: any) {
        if (++hasCheckCount > 5) throw new RangeError("Too many iterations");
        return false;
      },
      get(_t: any, p: any) {
        if (p === "length") return 0;
        return undefined;
      },
    });

    let threwTypeError = false;
    for (const fn of reduceCandidates) {
      hasCheckCount = 0;
      try {
        fn.call(emptyProxy, (a: any, b: any) => b);
      } catch (e) {
        if (e instanceof TypeError) {
          threwTypeError = true;
          break;
        }
      }
    }

    expect(threwTypeError).toBe(true);
  });
});
